// Lightweight Merkle root builder (conceptual)
class MerkleTree {
  constructor(){ this.leaves = []; this.rootHash = null; }
  addLeaf(data) { this.leaves.push(hash(data)); this.rootHash = this.computeRoot(); }
  computeRoot(){ // simplistic binary Merkle root placeholder
    let nodes = this.leaves.slice();
    while (nodes.length > 1) {
      const next = [];
      for (let i = 0; i < nodes.length; i += 2) {
        const a = nodes[i];
        const b = nodes[i+1] || a;
        next.push(hash(a + b));
      }
      nodes = next;
    }
    return nodes[0] || null;
  }
}
function hash(x){ // placeholder for a real crypto hash
  return require('crypto').createHash('sha256').update(x).digest('hex');
}
```

