## Code Example
```javascript
class LagMonitor {
  constructor(threshold, windowMs = 60000) {
    this.threshold = threshold;
    this.windowMs = windowMs;
    this.lagMap = new Map();
    this.lastAlert = new Map();
  }
  onMessage(partition, endOffset, committedOffset) {
    const lag = endOffset - committedOffset;
    const now = Date.now();
    this.lagMap.set(partition, { lag, ts: now });
    this.check(partition);
  }
  check(partition) {
    const entry = this.lagMap.get(partition);
    if (!entry) return;
    if (entry.lag > this.threshold && (Date.now() - entry.ts) >= this.windowMs) {
      this.emitAlert(partition, entry.lag);
      this.lastAlert.set(partition, Date.now());
      // reset timer for next alert window
      this.lagMap.set(partition, { lag: entry.lag, ts: Date.now() });
    }
  }
  emitAlert(partition, lag) {
    // publish to 'lag_alerts' with partition, lag, timestamp, host
  }
}
```

