// Pseudocode: per-tenant limiter in consume loop
let buckets = new Map<string, {tokens:number, lastRefill:number}>();
function allow(tenantId){
  const now=Date.now();
  const b = buckets.get(tenantId) ?? {tokens:0, lastRefill:now};
  const elapsed=(now-b.lastRefill)/1000;
  b.tokens = Math.min(200, b.tokens + 100*elapsed);
  b.lastRefill = now;
  buckets.set(tenantId,b);
  if(b.tokens>=1){ b.tokens-=1; return true;} return false;
}
```

