## Code Example
```javascript
// Pseudo: Exactly-once consumer with transactional outbox
async function processEvent(event, consumer, producer) {
  const globalId = `${event.region}||${event.partition}||${event.offset}`;

  // Check dedup store
  if (await dedupStore.exists(globalId)) {
    await consumer.commitOffsets([{ topic: event.topic, partition: event.partition, offset: event.offset + 1 }]);
    return;
  }

  // Transaction: write audit + commit offset
  await producer.beginTransaction();
  try {
    await writeToAuditTable(globalId, event.payload);
    await dedupStore.set(globalId, { ttl: 86400 });
    await producer.sendOffsetsToTransaction([{ topic: event.topic, partition: event.partition, offset: event.offset + 1 }], consumerGroupId);
    await producer.commitTransaction();
  } catch (err) {
    await producer.abortTransaction();
    throw err;
  }
}
```

