## Code Example
```javascript
class LagController {
  constructor(targetLag = 1000, windowSize = 10) {
    this.targetLag = targetLag;
    this.windowSize = windowSize;
    this.lagWindow = new Map(); // partition -> lag samples[]
    this.inFlight = new Map();  // partition -> current in-flight permits
  }

  recordLag(partition, lag) {
    if (!this.lagWindow.has(partition)) {
      this.lagWindow.set(partition, []);
    }
    const samples = this.lagWindow.get(partition);
    samples.push(lag);
    if (samples.length > this.windowSize) samples.shift();
  }

  getAverageLag(partition) {
    const samples = this.lagWindow.get(partition) || [];
    return samples.length ? samples.reduce((a, b) => a + b, 0) / samples.length : 0;
  }

  shouldThrottle(partition) {
    return this.getAverageLag(partition) > this.targetLag;
  }

  adjustThrottle(partition) {
    const avgLag = this.getAverageLag(partition);
    const currentInFlight = this.inFlight.get(partition) || 10;

    if (avgLag > this.targetLag) {
      // Reduce fetch rate: decrease in-flight permits
      const reduced = Math.max(1, Math.floor(currentInFlight * 0.8));
      this.inFlight.set(partition, reduced);
    } else {
      // Ramp up slowly when lag is healthy
      const increased = Math.min(100, Math.floor(currentInFlight * 1.2));
      this.inFlight.set(partition, increased);
    }
    return this.inFlight.get(partition);
  }
}

// Minimal canary test
async function canaryTest() {
  const controller = new LagController(1000);
  const partitions = [0, 1, 2, 3];

  // Simulate burst: spike lag across all partitions
  for (const p of partitions) {
    controller.recordLag(p, 5000); // burst above target
  }

  // Verify throttling triggers
  const allThrottled = partitions.every(p => controller.shouldThrottle(p));
  console.log(`Throttle triggered: ${allThrottled}`);

  // Adjust and verify permits decrease
  partitions.forEach(p => {
    const permits = controller.adjustThrottle(p);
    console.log(`Partition ${p}: permits = ${permits}`);
  });
}
```

## Expected Answer Elements
- **Data structures**: Lag sample window per partition, in-flight permit tracker, target threshold
- **Triggers**: Timer-based lag sampling, configurable poll interval, lag spike detection
- **Canary test**: Burst generator simulating traffic spike, assertion that lag stabilizes within target

