// Tenant-scoped schema validation pipeline
class TenantSchemaValidator {
  constructor(tenantRegistry, compatibilityChecker) {
    this.tenantRegistry = tenantRegistry;
    this.compatibilityChecker = compatibilityChecker;
  }

  async validate(tenantId, payload) {
    const schemaVersion = await this.tenantRegistry.getVersion(tenantId);
    const schema = await this.tenantRegistry.getSchema(tenantId, schemaVersion);

    const validationResult = schema.validate(payload);
    if (!validationResult.valid) {
      throw new SchemaValidationError(validationResult.errors);
    }

    return { valid: true, schemaVersion };
  }

  async upgradeSchema(tenantId, newSchema) {
    const currentVersion = await this.tenantRegistry.getVersion(tenantId);
    const isCompatible = await this.compatibilityChecker.check(
      currentVersion,
      newSchema
    );

    if (!isCompatible.backwardCompatible) {
      throw new IncompatibleSchemaError('Schema not backward compatible');
    }

    const newVersion = await this.tenantRegistry.registerSchema(
      tenantId,
      newSchema
    );

    await this.rollback.scheduleRollback(tenantId, currentVersion);
    return newVersion;
  }
}
```

