```javascript
class WindowJoiner {
  constructor(options = {}) {
    this.windowSizeMs = options.windowSizeMs || 10000;
    this.latenessMs = options.latenessMs || 5000;
    this.seenClicks = new Map();
    this.seenImpressions = new Map();
    this.pendingJoins = new Map();
    this.watermarks = { clicks: 0, impressions: 0 };
    this.dedupeStore = new Map();
    this.committedOffsets = new Map();
    this.emittedRecords = [];
  }

  getWindowStart(timestamp) {
    return Math.floor(timestamp / this.windowSizeMs) * this.windowSizeMs;
  }

  getWindowEnd(timestamp) {
    return this.getWindowStart(timestamp) + this.windowSizeMs;
  }

  getKey(userId, timestamp) {
    const windowStart = this.getWindowStart(timestamp);
    return `${userId}|${windowStart}`;
  }

  onEvent(topic, event, partition = 0) {
    const key = this.getKey(event.userId, event.timestamp);
    const dedupeKey = `${topic}:${event.messageId}`;

    if (this.dedupeStore.has(dedupeKey)) {
      return { status: 'deduped', key };
    }
    this.dedupeStore.set(dedupeKey, true);

    const seenStore = topic === 'clicks' ? this.seenClicks : this.seenImpressions;
    if (!seenStore.has(key)) {
      seenStore.set(key, new Set());
    }
    seenStore.get(key).add(event.messageId);

    if (!this.pendingJoins.has(key)) {
      this.pendingJoins.set(key, {
        userId: event.userId,
        windowStart: this.getWindowStart(event.timestamp),
        windowEnd: this.getWindowEnd(event.timestamp),
        clicks: null,
        impressions: null
      });
    }

    const pending = this.pendingJoins.get(key);
    if (topic === 'clicks') {
      pending.clicks = event;
    } else {
      pending.impressions = event;
    }

    this.tryEmit(key);

    return { status: 'processed', key };
  }

  onWatermark(topic, watermark) {
    this.watermarks[topic] = watermark;

    const minWatermark = Math.min(this.watermarks.clicks, this.watermarks.impressions);
    if (minWatermark > 0) {
      this.processLateEvents(minWatermark);
    }

    return { watermarks: this.watermarks, minWatermark };
  }

  tryEmit(key) {
    const pending = this.pendingJoins.get(key);

    if (pending && pending.clicks && pending.impressions) {
      this.emitJoined({
        userId: pending.userId,
        click: pending.clicks,
        impression: pending.impressions,
        windowStart: pending.windowStart,
        windowEnd: pending.windowEnd,
        joinTime: Date.now()
      });

      this.pendingJoins.delete(key);
      return true;
    }
    return false;
  }

  emitJoined(record) {
    const output = {
      messageId: `joined_${record.click.messageId}_${record.impression.messageId}`,
      userId: record.userId,
      clickId: record.click.messageId,
      impressionId: record.impression.messageId,
      clickData: record.click.data,
      impressionData: record.impression.data,
      windowStart: record.windowStart,
      windowEnd: record.windowEnd,
      timestamp: Date.now()
    };

    this.emittedRecords.push(output);
    return output;
  }

  processLateEvents(watermark) {
    const lateThreshold = watermark - this.latenessMs;

    for (const [key, pending] of this.pendingJoins) {
      if (pending.windowEnd < lateThreshold) {
        const hasPartial = pending.clicks || pending.impressions;
        if (hasPartial) {
          this.emitJoined({
            ...pending,
            late: true,
            lateReason: pending.windowEnd < lateThreshold ? 'window_expired' : null
          });
          this.pendingJoins.delete(key);
        }
      }
    }
  }

  async commitOffsets(offsets, consumer) {
    const results = [];

    for (const [topicPartition, offsetMeta] of Object.entries(offsets)) {
      const commitOffset = offsetMeta.offset + 1;
      const partition = offsetMeta.partition;

      this.committedOffsets.set(topicPartition, commitOffset);

      if (consumer && typeof consumer.commit === 'function') {
        await consumer.commit({
          [topicPartition]: { offset: commitOffset, partition }
        });
      }

      results.push({ topicPartition, committedOffset: commitOffset });
    }

    return { committed: results, totalCommitted: results.length };
  }

  getState() {
    return {
      pendingJoins: this.pendingJoins.size,
      deduplicationEntries: this.dedupeStore.size,
      watermarks: this.watermarks,
      emittedRecords: this.emittedRecords.length
    };
  }
}

function runCanaryTest() {
  console.log('Running canary test...');

  const joiner = new WindowJoiner({ windowSizeMs: 10000, latenessMs: 5000 });

  joiner.onEvent('clicks', { 
    userId: 'u1', 
    messageId: 'c1', 
    timestamp: 10000,
    data: { url: '/home' }
  });

  joiner.onEvent('impressions', { 
    userId: 'u1', 
    messageId: 'i1', 
    timestamp: 12000,
    data: { adId: 'ad123' }
  });

  joiner.onWatermark('clicks', 15000);
  joiner.onWatermark('impressions', 15000);

  const state = joiner.getState();
  const joined = joiner.emittedRecords[0];

  console.assert(joined, 'Should emit joined record');
  console.assert(joined.userId === 'u1', 'User ID should match');
  console.assert(joined.clickId === 'c1', 'Click ID should match');
  console.assert(joined.impressionId === 'i1', 'Impression ID should match');

  console.log('Canary test passed!');
  console.log('Joined record:', JSON.stringify(joined, null, 2));

  return { success: true, state, joinedRecord: joined };
}

if (require.main === module) {
  runCanaryTest();
}

module.exports = { WindowJoiner, runCanaryTest };
```

