  onMessage(msg) {
    const { tenantId, globalSeq } = msg.meta;
    if (!this.buff.has(tenantId)) this.buff.set(tenantId, new Map());
    const map = this.buff.get(tenantId);
    map.set(globalSeq, msg);
    this.flush(tenantId);
  }
