class SchemaCache {
  constructor(fetcher, ttlMs = 60000) {
    this.fetcher = fetcher; this.ttl = ttlMs; this.store = new Map();
  }
  async get(version) {
    const entry = this.store.get(version);
    const now = Date.now();
    if (entry && (now - entry.ts) < this.ttl) return entry.validate;
    const schema = await this.fetcher(version);
    const Ajv = require('ajv');
