class GlobalDedupeStore {
  constructor(redisClient, ttlSeconds = 86400) {
    this.redis = redisClient;
    this.ttl = ttlSeconds;
  }

  async isDuplicate(orderId, region, timestamp) {
    const key = `${orderId}:${region}`;
    const existing = await this.redis.get(key);

    if (existing && existing >= timestamp) {
      return true;
    }

    await this.redis.set(key, timestamp, 'EX', this.ttl);
    return false;
  }
}
