  constructor(threshold, sinks) {
    this.threshold = threshold;
    this.sinks = sinks;
    this.seenIds = new LRUCache(10000);
  }

  process(message) {
    const msgId = message.messageId;
    if (this.seenIds.has(msgId)) return; // skip duplicates

    const record = this.normalize(message);
    const sink = record.value > this.threshold ? this.sinks.alerts : this.sinks.default;
    sink.write(record);
