class WatermarkManager {
  constructor(maxLagMs = 60000) {
    this.maxLagMs = maxLagMs;
    this.topicWatermarks = new Map();
    this.offsetStore = new Map();
  }

  processMessage(topic, partition, offset, timestamp) {
    const key = `${topic}-${partition}`;
    const currentWatermark = this.topicWatermarks.get(key) || 0;

    if (timestamp > currentWatermark) {
      this.topicWatermarks.set(key, timestamp);
    }

    const watermark = this.topicWatermarks.get(key);
    const lag = watermark - timestamp;

    this.offsetStore.set(key, offset);

    if (lag > this.maxLagMs) {
      return { route: 'late_events', topic, partition, offset };
    }

    return { route: 'main', topic, partition, offset };
  }
}
```

This implementation maintains per-topic watermarks, routes late messages appropriately, tracks offsets, and supports at-least-once delivery through committed offset storage.

