const WINDOW_MS = 10 * 60 * 1000;
const LATE_MS = 2 * 60 * 1000;

function onMessage(msg, commitFn) {
  const { userId, ts, score } = JSON.parse(msg.value);
  const windowStart = Math.floor(ts / WINDOW_MS) * WINDOW_MS;
  const windowEnd = windowStart + WINDOW_MS;
  const stateKey = `${userId}:${windowStart}`;

  if (ts < watermark - LATE_MS) return; // drop late

