class WindowedCTR {
  constructor(windowSizeMs = 5000, ttlMs = 60000) {
    this.windowSizeMs = windowSizeMs;
    this.ttlMs = ttlMs;
    this.state = new Map();
  }

  processMessage(msg) {
    const { userId, type, timestamp } = JSON.parse(msg.value);
    const windowStart = Math.floor(timestamp / this.windowSizeMs) * this.windowSizeMs;
    const key = `${userId}:${windowStart}`;

    if (!this.state.has(key)) {
      this.state.set(key, { clicks: 0, impressions: 0, emitted: false, lastUpdate: Date.now() });
    }
    const window = this.state.get(key);
    if (type === 'click') window.clicks++;
    if (type === 'impression') window.impressions++;
    window.lastUpdate = Date.now();

    if (!window.emitted && Date.now() - windowStart >= this.windowSizeMs) {
      this.emitCTR(key, window);
      window.emitted = true;
    }
  }

  commitOffsets(offsets) { /* persist consumer offsets */ }
  windowState() { return Array.from(this.state.entries()); }
}
