class RateStore {
  constructor(ttlMs) {
    this.ttlMs = ttlMs;
    this.store = new Map();
  }
  get(key, minute) {
    return this.store.get(`${key}:${minute}`) ?? 0;
  }
  increment(key, minute) {
    const entry = this.store.get(`${key}:${minute}`) ?? { count: 0, timestamp: Date.now() };
    entry.count++;
    this.store.set(`${key}:${minute}`, entry);
    return entry.count;
  }
  prune() {
    const now = Date.now();
    for (const [key, entry] of this.store.entries()) {
      if (now - entry.timestamp > this.ttlMs) {
        this.store.delete(key);
      }
    }
  }
}

