class CrossTopicEnrichmentSink {
  constructor(windowSize = 5 * 60 * 1000, lateTolerance = 2 * 60 * 1000) {
    this.store = new Map();
    this.emittedKeys = new Set();
    this.windowSize = windowSize;
    this.lateTolerance = lateTolerance;
  }

  onMessage(ctx, msg) {
    const { topic, userId, timestamp, data } = msg;
    const key = `${topic}:${userId}:${this.getWindowId(timestamp)}`;

    if (this.emittedKeys.has(key)) return;

    if (!this.store.has(userId)) {
      this.store.set(userId, { clicks: [], impressions: [], firstSeen: Date.now() });
    }

    const buffer = this.store.get(userId);
    buffer[topic].push({ ...data, timestamp });

    this.tryEnrich(userId, key);
  }

  tryEnrich(userId, key) {
    const buffer = this.store.get(userId);
    if (buffer.clicks.length > 0 && buffer.impressions.length > 0) {
      const enriched = {
        userId,
        clicks: buffer.clicks,
        impressions: buffer.impressions,
        enrichedAt: Date.now()
      };
      this.emittedKeys.add(key);
      buffer.clicks = [];
      buffer.impressions = [];
      return enriched;
    }
  }

  getWindowId(timestamp) {
    return Math.floor(timestamp / this.windowSize);
  }

  commitOffsets() {
    this.emittedKeys.clear();
  }

  enrichmentStore() {
    return this.store;
  }
}
```

