// simplified token bucket sketch
class TokenBucket {
  constructor(rate, capacity) {
    this.rate = rate;
    this.capacity = capacity;
    this.tokens = capacity;
    this.lastRefill = Date.now();
  }

  allow(n = 1) {
    this.refill();
    if (this.tokens >= n) {
      this.tokens -= n;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const elapsed = (now - this.lastRefill) / 1000;
    this.tokens = Math.min(this.capacity, this.tokens + elapsed * this.rate);
    this.lastRefill = now;
  }
}

// Global limiter wrapping per-tenant buckets
class TenantRateController {
  constructor(tenants, globalRate) {
    this.buckets = new Map();
    this.globalLimiter = new TokenBucket(globalRate, globalRate * 2);
    for (const [id, quota] of tenants) {
      this.buckets.set(id, new TokenBucket(quota.rate, quota.burst));
    }
  }

  tryProcess(tenantId, n = 1) {
    const bucket = this.buckets.get(tenantId);
    if (!bucket || !bucket.allow(n)) return false;
    if (!this.globalLimiter.allow(n)) {
      bucket.tokens += n; // rollback tenant token
      return false;
    }
    return true;
  }
}
```

