- Exactly-once semantics through idempotent producers and transactional writes
- Failover mechanisms with automatic leader election and log replay

## Code Example

```javascript
// KCNA publisher with idempotency and cross-region coordination
class KCNAPublisher {
  constructor(tenantId, region, globalSequencer) {
    this.tenantId = tenantId;
    this.region = region;
    this.sequencer = globalSequencer;
    this.dedupStore = new Map();
  }

  async publishEvent(event) {
    const messageId = `${this.tenantId}:${this.region}:${event.id}`;

    // Idempotency check
    if (this.dedupStore.has(messageId)) {
      return { status: 'duplicate', seq: null };
    }

    // Get global sequence for ordering
    const globalSeq = await this.sequencer.getNextSequence(
      this.tenantId, this.region
    );

    const enrichedEvent = {
      ...event,
      tenantId: this.tenantId,
      region: this.region,
      globalSequence: globalSeq,
      timestamp: Date.now()
    };

    // Write to local log with transaction
    await this.writeToLog(enrichedEvent);
    this.dedupStore.set(messageId, true);

    // Trigger cross-region replication
    await this.replicateToPeerRegion(enrichedEvent);

    return { status: 'success', seq: globalSeq };
  }

  async writeToLog(event) {
    // Transactional write to tenant-specific partition
    const partition = this.getPartition(event.tenantId);
    return partition.append(event, { transactional: true });
  }

  async replicateToPeerRegion(event) {
    // Async replication to peer region
    const peerRegion = this.region === 'A' ? 'B' : 'A';
    return this.replicator.send(peerRegion, event);
  }
}

// Global sequencer for cross-region ordering
class GlobalSequencer {
  constructor() {
    this.counters = new Map(); // tenantId -> sequence
  }

  async getNextSequence(tenantId, region) {
    const key = `${tenantId}`;
    const current = this.counters.get(key) || 0;
    const next = current + 1;
    this.counters.set(key, next);
    return next;
  }
}
```

